            border-right: 1px solid #1a1f3a;
            overflow-y: auto;
        }

        .player-card {
            background: linear-gradient(135deg, rgba(255, 70, 85, 0.1) 0%, rgba(100, 150, 255, 0.1) 100%);
            border: 1px solid #ff4655;
            border-radius: 8px;
            padding: 1.5rem;
            margin-bottom: 2rem;
            transition: all 0.3s ease;
        }

        .player-card:hover {
            box-shadow: 0 0 20px rgba(255, 70, 85, 0.3);
            transform: translateY(-5px);
            border-color: #ff6b7a;
        }

        .player-name {
            font-size: 1.4rem;
            font-weight: bold;
            color: #ff4655;
            margin-bottom: 1rem;
            text-transform: uppercase;
